sql:
SELECT SUM(sales_volume) AS total_sales_volume
FROM sales_by_country
WHERE album_id = 1;

external_knowledge:
- "Top three albums" means the albums with the highest total sales, implying that the sales volumes are used for ranking; 
- "Accessed by administrators" implies that only albums accessed by users with the role 'admin' should be considered;
- "Certified at least twice" means that only albums with a certification count of 2 or more should be included.

sql:
SELECT SUM(sales_volume) AS total_sales_volume
FROM sales_by_country
WHERE album_id IN (
    SELECT album_id FROM albums WHERE artist_id = (
        SELECT artist_id FROM artists WHERE artist_name = 'Led Zeppelin'
    )
)
AND country_code = 'US';

SELECT SUM(sbc.sales_volume) AS total_sales_volume
FROM sales_by_country sbc
WHERE sbc.country_code = 'US';

SELECT SUM(sales_volume) AS total_sales_volume
FROM sales_by_country
WHERE album_id = 1 AND country_code = 'JP';
